/* 要素の取得の例 */

// idによる要素の取得
var elementById = document.getElementById('myId');

// class名による要素の取得
var elementsByClassName = document.getElementsByClassName('myClass');

// タグ名による要素の取得
var elementsByTagName = document.getElementsByTagName('div');

// CSSセレクタによる要素の取得 (最初の一つ)
var elementByQuery = document.querySelector('.myClass');

// CSSセレクタによる要素の取得 (すべて)
var elementsByQueryAll = document.querySelectorAll('.myClass');

/* 属性の変更の例 */

// idによる要素の取得
var element = document.getElementById('myId');

// 属性の追加・変更
element.setAttribute('data-custom', 'customValue');

// 属性の削除
element.removeAttribute('data-custom');

// class名の変更
element.className = 'newClass';

// idの変更
element.id = 'newId';

/* クラスの操作の例 */

// idによる要素の取得
var element = document.getElementById('myId');

// クラスの追加
element.classList.add('newClass');

// クラスの削除
element.classList.remove('newClass');

// クラスの存在チェック
element.classList.contains('newClass');

// クラスの存在による追加・削除（トグル操作）
element.classList.toggle('newClass');

/* イベントの設定の例 */

// idによる要素の取得
var element = document.getElementById('myId');

// イベントリスナの追加
element.addEventListener('click', function(event) {
  alert('Element was clicked!');
});

// イベントリスナの削除
var listener = function(event) {
  alert('Element was clicked!');
};
element.addEventListener('click', listener);
element.removeEventListener('click', listener);
